import{_ as t,o as e,c as l,aw as i}from"./chunks/framework.DLufY-ao.js";const h=JSON.parse('{"title":"Методологии разработки","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/methodology/methodology.md","filePath":"wiki/dev-commit/theory/methodology-dev/methodology/methodology.md"}'),a={name:"wiki/dev-commit/theory/methodology-dev/methodology/methodology.md"};function r(n,o,s,d,m,g){return e(),l("div",null,[...o[0]||(o[0]=[i('<h1 id="методологии-разработки" tabindex="-1">Методологии разработки <a class="header-anchor" href="#методологии-разработки" aria-label="Permalink to &quot;Методологии разработки&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Методология разработки</p><ul><li><strong>Методология разработки</strong> - организация труда, включающая идеологические принципы, план, контроль над процессами, подход к сотрудникам</li></ul></div><h2 id="методологии" tabindex="-1">Методологии <a class="header-anchor" href="#методологии" aria-label="Permalink to &quot;Методологии&quot;">​</a></h2><ul><li><strong>RUP</strong> (Rational Unified Process) - рациональный (итеративный подход). ПО выходит с уменьшенной функциональностью, чтобы занять нишу на рынке и противостоять конкурентам, после чего дорабатывается</li><li><strong>Crystal Clear</strong> - подход с уравниванием разработчиков в коллективе. Каждая команда является набором людей с разным уровнем знаний, разными умениями и опытом</li><li><strong>Spiral</strong> - спиральный метод. Раннее выявление и уменьшение проектных рисков</li><li><strong>DSDM</strong> (Dynamic Systems Development Model) - динамическая модель. При планировании в самом начале невозможно понимать всех тонкостей разработки, поэтому весь процесс — исследовательская работа</li><li><strong>FDD</strong> (Feature Driven Development) - методология, рассматривающая будущие изменения. Процесс для обеспечения масштабируемости и повторяемости, при этом поощряющий творчество и инновации</li><li><strong>JAD</strong> (Joint Application Development) - ориентированный на пользователя подход. Максимальная занятость в разработке конечного пользователя</li><li><strong>RAD</strong> (Rapid Application Development) - модель быстрой разработки</li><li><strong>XP</strong> (Extreme Programming) - экстремальная разработка в динамической среде</li><li><strong>LD</strong> (Lean Development) - метод, предполагающий бережное отношение ко всем участникам процесса</li></ul>',5)])])}const p=t(a,[["render",r]]);export{h as __pageData,p as default};
